"""
风险管理模块 - 核心风控系统

与策略解耦的独立风控系统
"""

import pandas as pd
import numpy as np
from datetime import datetime, time
from typing import Dict, List, Optional, Callable
from dataclasses import dataclass
from enum import Enum
import logging

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)


class RiskLevel(Enum):
    """风险等级"""
    PASS = "PASS"
    WARNING = "WARNING"
    BLOCK = "BLOCK"


@dataclass
class RiskCheckResult:
    """风控检查结果"""
    rule_name: str
    level: RiskLevel
    message: str
    details: Dict = None


@dataclass
class Order:
    """订单"""
    symbol: str
    action: str  # BUY/SELL
    shares: int
    price: float
    order_type: str = "MARKET"
    strategy_name: str = ""


@dataclass
class Position:
    """持仓"""
    symbol: str
    shares: int
    avg_cost: float
    market_value: float


@dataclass
class Account:
    """账户"""
    cash: float
    positions: Dict[str, Position]
    total_value: float
    daily_pnl: float


class RiskRule:
    """风控规则基类"""

    def __init__(self, name: str, enabled: bool = True):
        self.name = name
        self.enabled = enabled

    def check(self, order: Order, account: Account, 
              market_data: Dict) -> RiskCheckResult:
        raise NotImplementedError


class PositionLimitRule(RiskRule):
    """
    仓位限制规则

    限制单票最大仓位和总仓位
    """

    def __init__(self, max_single_position: float = 0.2,
                 max_total_position: float = 0.95):
        super().__init__("PositionLimit")
        self.max_single_position = max_single_position
        self.max_total_position = max_total_position

    def check(self, order: Order, account: Account, 
              market_data: Dict) -> RiskCheckResult:
        if not self.enabled:
            return RiskCheckResult(self.name, RiskLevel.PASS, "规则已禁用")

        # 计算当前持仓
        current_position = account.positions.get(order.symbol, None)
        current_shares = current_position.shares if current_position else 0

        # 计算交易后的持仓
        if order.action == "BUY":
            new_shares = current_shares + order.shares
        else:
            new_shares = current_shares - order.shares

        new_value = new_shares * order.price
        new_ratio = new_value / account.total_value if account.total_value > 0 else 0

        # 检查单票仓位
        if new_ratio > self.max_single_position:
            return RiskCheckResult(
                self.name, RiskLevel.BLOCK,
                f"单票仓位 {new_ratio*100:.1f}% 超过限制 {self.max_single_position*100:.1f}%",
                {"current_ratio": new_ratio, "limit": self.max_single_position}
            )

        # 检查总仓位
        total_position_value = sum(p.market_value for p in account.positions.values())
        if order.action == "BUY":
            total_position_value += order.shares * order.price
        total_ratio = total_position_value / account.total_value if account.total_value > 0 else 0

        if total_ratio > self.max_total_position:
            return RiskCheckResult(
                self.name, RiskLevel.BLOCK,
                f"总仓位 {total_ratio*100:.1f}% 超过限制 {self.max_total_position*100:.1f}%",
                {"current_ratio": total_ratio, "limit": self.max_total_position}
            )

        return RiskCheckResult(
            self.name, RiskLevel.PASS,
            f"仓位检查通过，单票 {new_ratio*100:.1f}%，总仓位 {total_ratio*100:.1f}%"
        )


class DailyLossLimitRule(RiskRule):
    """
    单日亏损限制
    """

    def __init__(self, max_daily_loss_pct: float = 0.02):
        super().__init__("DailyLossLimit")
        self.max_daily_loss_pct = max_daily_loss_pct

    def check(self, order: Order, account: Account, 
              market_data: Dict) -> RiskCheckResult:
        if not self.enabled:
            return RiskCheckResult(self.name, RiskLevel.PASS, "规则已禁用")

        # 检查当日亏损
        daily_loss_pct = -account.daily_pnl / account.total_value if account.total_value > 0 else 0

        if daily_loss_pct > self.max_daily_loss_pct:
            return RiskCheckResult(
                self.name, RiskLevel.BLOCK,
                f"当日亏损 {daily_loss_pct*100:.1f}% 超过限制 {self.max_daily_loss_pct*100:.1f}%",
                {"daily_loss": daily_loss_pct, "limit": self.max_daily_loss_pct}
            )

        return RiskCheckResult(
            self.name, RiskLevel.PASS,
            f"当日亏损 {daily_loss_pct*100:.1f}% 在限制范围内"
        )


class TradingTimeRule(RiskRule):
    """
    交易时间限制
    """

    def __init__(self, 
                 allow_pre_market: bool = False,
                 allow_after_hours: bool = False,
                 restricted_times: List[Tuple[time, time]] = None):
        super().__init__("TradingTime")
        self.allow_pre_market = allow_pre_market
        self.allow_after_hours = allow_after_hours
        self.restricted_times = restricted_times or []

    def check(self, order: Order, account: Account, 
              market_data: Dict) -> RiskCheckResult:
        if not self.enabled:
            return RiskCheckResult(self.name, RiskLevel.PASS, "规则已禁用")

        now = datetime.now().time()

        # A股交易时间
        morning_start = time(9, 30)
        morning_end = time(11, 30)
        afternoon_start = time(13, 0)
        afternoon_end = time(15, 0)

        is_trading_time = (
            (morning_start <= now <= morning_end) or
            (afternoon_start <= now <= afternoon_end)
        )

        if not is_trading_time:
            return RiskCheckResult(
                self.name, RiskLevel.BLOCK,
                f"当前时间 {now} 不在交易时段",
                {"current_time": now}
            )

        # 检查限制时段
        for start, end in self.restricted_times:
            if start <= now <= end:
                return RiskCheckResult(
                    self.name, RiskLevel.WARNING,
                    f"当前时间 {now} 在限制时段内",
                    {"restricted_period": f"{start} - {end}"}
                )

        return RiskCheckResult(
            self.name, RiskLevel.PASS,
            f"交易时间检查通过"
        )


class PriceLimitRule(RiskRule):
    """
    价格限制规则

    防止以异常价格下单
    """

    def __init__(self, max_price_deviation: float = 0.05):
        super().__init__("PriceLimit")
        self.max_price_deviation = max_price_deviation

    def check(self, order: Order, account: Account, 
              market_data: Dict) -> RiskCheckResult:
        if not self.enabled:
            return RiskCheckResult(self.name, RiskLevel.PASS, "规则已禁用")

        # 获取最新市场价
        last_price = market_data.get('last_price', order.price)

        if last_price <= 0:
            return RiskCheckResult(
                self.name, RiskLevel.BLOCK,
                "无法获取有效市场价格",
                {}
            )

        # 检查价格偏离
        price_deviation = abs(order.price - last_price) / last_price

        if price_deviation > self.max_price_deviation:
            return RiskCheckResult(
                self.name, RiskLevel.WARNING,
                f"订单价格 {order.price} 偏离市场价 {last_price} 超过 {self.max_price_deviation*100}%",
                {"order_price": order.price, "market_price": last_price, 
                 "deviation": price_deviation}
            )

        return RiskCheckResult(
            self.name, RiskLevel.PASS,
            f"价格检查通过，偏离 {price_deviation*100:.2f}%"
        )


class SelfTradeRule(RiskRule):
    """
    自成交检查

    防止同一策略同时发出买卖信号导致自成交
    """

    def __init__(self, pending_orders: List[Order] = None):
        super().__init__("SelfTrade")
        self.pending_orders = pending_orders or []

    def check(self, order: Order, account: Account, 
              market_data: Dict) -> RiskCheckResult:
        if not self.enabled:
            return RiskCheckResult(self.name, RiskLevel.PASS, "规则已禁用")

        # 检查是否有相反方向的待成交订单
        for pending in self.pending_orders:
            if (pending.symbol == order.symbol and 
                pending.action != order.action):
                return RiskCheckResult(
                    self.name, RiskLevel.WARNING,
                    f"存在相反方向的待成交订单，可能导致自成交",
                    {"pending_order": pending}
                )

        return RiskCheckResult(
            self.name, RiskLevel.PASS,
            "无自成交风险"
        )


class RiskManager:
    """
    风险管理器

    统一管理所有风控规则
    """

    def __init__(self):
        self.rules: List[RiskRule] = []
        self.block_on_warning = False  # 是否在WARNING时阻断

    def add_rule(self, rule: RiskRule):
        """添加风控规则"""
        self.rules.append(rule)
        logger.info(f"添加风控规则: {rule.name}")

    def check_order(self, order: Order, account: Account, 
                    market_data: Dict) -> List[RiskCheckResult]:
        """
        检查订单

        Returns:
            所有规则的检查结果
        """
        results = []

        for rule in self.rules:
            try:
                result = rule.check(order, account, market_data)
                results.append(result)

                if result.level == RiskLevel.BLOCK:
                    logger.warning(f"风控阻断 [{rule.name}]: {result.message}")
                elif result.level == RiskLevel.WARNING:
                    logger.warning(f"风控警告 [{rule.name}]: {result.message}")

            except Exception as e:
                logger.error(f"风控规则 {rule.name} 执行异常: {e}")
                results.append(RiskCheckResult(
                    rule.name, RiskLevel.BLOCK,
                    f"规则执行异常: {e}",
                    {"error": str(e)}
                ))

        return results

    def can_execute(self, results: List[RiskCheckResult]) -> bool:
        """
        判断订单是否可以执行
        """
        for result in results:
            if result.level == RiskLevel.BLOCK:
                return False
            if result.level == RiskLevel.WARNING and self.block_on_warning:
                return False
        return True

    def get_default_manager() -> 'RiskManager':
        """
        获取默认配置的风控管理器
        """
        manager = RiskManager()

        # 添加默认规则
        manager.add_rule(PositionLimitRule(
            max_single_position=0.2,
            max_total_position=0.95
        ))

        manager.add_rule(DailyLossLimitRule(
            max_daily_loss_pct=0.02
        ))

        manager.add_rule(TradingTimeRule())

        manager.add_rule(PriceLimitRule(
            max_price_deviation=0.05
        ))

        return manager

